      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: 'test@example.com' },
      ],
    },
    subject,
    from: { email: 'test@example.com', raw: 'test@example.com' },
    to: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
    date: new Date('2025-09-15T10:00:00Z'),
    bodyPlain: 'Test email body',
    processingPriority: 0,
    isProcessed: false,
  };
}

/**
 * Helper to create mock ClassificationResult
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function createMockClassificationResult(): any {
  return {
    selectedLabels: [
      {
        category: 'WORK',
        subtype: 'WORK.MEETING',
        confidence: 0.85,
        score: 0.85,
        isPrimary: true,
        labelOrder: 1,
        selectionRationale: 'High confidence work classification',
      },
    ],
    candidateScores: {
      WORK: {
        score: 0.85,
        confidence: 0.85,
        decision: 'selected',
      },
    },
    selectionSummary: {
      totalLabels: 1,
      primaryCategory: 'WORK',
      confidenceRange: [0.85, 0.85],
      selectionMethod: 'single_label',
      needsAi: false,
    },
    needsAiClassification: false,
    processingDurationMs: 8300,
  };
}

/**
 * Mock CategoryConfiguration for pipeline initialization
 * Using valid minimal config from fixtures
 */
const mockProcessingConfig = validMinimalCategoryConfig;

describe('test-pipeline CLI Integration Tests', () => {
  let mockFetchEmailById: jest.MockedFunction<typeof emailQuery.fetchEmailById>;
  let mockFetchUnclassifiedEmails: jest.MockedFunction<typeof emailQuery.fetchUnclassifiedEmails>;
  let mockFetchEmailsByDateRange: jest.MockedFunction<typeof emailQuery.fetchEmailsByDateRange>;
  let mockSaveClassificationResult: jest.MockedFunction<typeof classificationWriter.saveClassificationResult>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Setup mocks
    mockFetchEmailById = emailQuery.fetchEmailById as jest.MockedFunction<typeof emailQuery.fetchEmailById>;
    mockFetchUnclassifiedEmails = emailQuery.fetchUnclassifiedEmails as jest.MockedFunction<
      typeof emailQuery.fetchUnclassifiedEmails
    >;
    mockFetchEmailsByDateRange = emailQuery.fetchEmailsByDateRange as jest.MockedFunction<
      typeof emailQuery.fetchEmailsByDateRange
    >;
    mockSaveClassificationResult = classificationWriter.saveClassificationResult as jest.MockedFunction<
      typeof classificationWriter.saveClassificationResult
    >;
  });

  describe('Argument Parsing and Validation', () => {
    test('should validate required mode argument', () => {
      expect(() => parseArguments([])).toThrow('Mode is required');
    });

    test('should validate mode values (single, batch, date-range)', () => {
      expect(() => parseArguments(['--mode', 'invalid'])).toThrow('Invalid mode');
    });

    test('should require message-id for single mode', () => {
      expect(() => parseArguments(['--mode', 'single'])).toThrow('message-id is required for single mode');
    });

    test('should require start and end dates for date-range mode', () => {
      expect(() => parseArguments(['--mode', 'date-range', '--start', '2025-09-01'])).toThrow(
        'Both start and end dates are required'
      );
    });

    test('should parse valid single mode arguments', () => {
      const args = parseArguments(['--mode', 'single', '--message-id', 'test-123']);

      expect(args).toEqual({
        mode: 'single',
        messageId: 'test-123',
        dryRun: false,
      });
    });

    test('should parse valid batch mode arguments with limit', () => {
      const args = parseArguments(['--mode', 'batch', '--limit', '10']);

      expect(args).toEqual({
        mode: 'batch',
        limit: 10,
        dryRun: false,
      });
    });

    test('should parse valid date-range mode arguments', () => {
      const args = parseArguments([
        '--mode',
        'date-range',
        '--start',
        '2025-09-01',
        '--end',
        '2025-09-30',
        '--limit',
        '50',
      ]);

      expect(args).toEqual({
        mode: 'date-range',
        startDate: '2025-09-01',
        endDate: '2025-09-30',
        limit: 50,
        dryRun: false,
      });
    });

    test('should recognize dry-run flag', () => {
      const args = parseArguments(['--mode', 'batch', '--dry-run']);

      expect(args.dryRun).toBe(true);
    });
  });

  describe('Single Email Processing', () => {
